#include<bits/stdc++.h>
#define ll long long
#define CI const int
using namespace std;
CI MAXN=1e3+5;
vector<int> MAP[MAXN];
int n,m,a[MAXN],k,vis[MAXN];
void DFS(int t)
{
	a[k]=max(a[k],t);
	for(int i=0;i<MAP[t].size();++i)
	{
		if(!vis[MAP[t][i]])
		{
			vis[MAP[t][i]]=true;
			DFS(MAP[t][i]);
		}
		
	}
}
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	scanf("%d%d",&n,&m);
	for(int i=1,u,v;i<=m;++i)
	{
		scanf("%d%d",&v,&u);
		MAP[v].push_back(u);
		
	}for(int i=1;i<=n;++i){
		for(int j=1;j<=n;++j)vis[j]=0;
		k=i;
		DFS(k);
		printf("%d ",a[k]);
	} 
	
	return false;
}
